{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream consumers, 2 million rows of production data, and external partner API contracts.",
    "bounded_context": "Shipment Fulfillment — the core context that owns Shipment lifecycle from creation through delivery. This change also ripples into Partner Integration (external APIs), Notification (per-recipient alerts), Routing/Dispatch (delivery planning), and Billing (cost allocation across recipients).",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "An aggregate root representing a single physical consignment moving through the delivery network. Owns its Recipients and delivery lifecycle." },
      { "term": "Recipient", "definition": "A value object (previously embedded, now a first-class entity within the Shipment aggregate) representing a person or entity who receives all or part of a Shipment. Has a name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preference", "definition": "A value object on Recipient capturing per-recipient instructions such as preferred time window, safe place authorization, signature requirement, or contactless delivery." },
      { "term": "Primary Recipient", "definition": "The designated default Recipient on a multi-recipient Shipment, used for backward compatibility and as the fallback contact for the courier." },
      { "term": "Recipient Cardinality", "definition": "The invariant that a Shipment must have at least one Recipient (minimum 1, no upper bound defined yet)." },
      { "term": "Partner API Contract", "definition": "The external-facing schema consumed by partner systems, currently encoding a single Recipient per Shipment. Any breaking change requires versioning or an adapter layer." },
      { "term": "Delivery Attempt", "definition": "A domain event recording a courier's attempt to deliver to a specific Recipient at a specific address. With multi-recipient, each attempt must be scoped to a Recipient." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment (e.g., Created, In Transit, Delivered, Failed). With multi-recipient, the aggregate status derivation rule must be redefined — is a Shipment 'Delivered' when ANY recipient receives, or when ALL do?" }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero Recipients has no delivery destination — it is physically and logically meaningless. The system is in a corrupt state if this occurs.",
      "testable_assertion": "Any attempt to create a Shipment with an empty Recipient list, or to remove the last Recipient from a Shipment, MUST be rejected with a domain error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a name, a valid address, and a phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data elements required for a courier to execute a delivery. Missing any one makes delivery impossible and corrupts downstream processes (routing, notifications).",
      "testable_assertion": "Creating or updating a Recipient with a null/empty name, address, or phone number MUST be rejected at the aggregate boundary."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MUST be uniquely identifiable (no duplicate address+name combinations within the same Shipment).",
      "invariant": true,
      "invariant_justification": "Duplicate Recipients within the same Shipment would cause double-delivery attempts, billing errors, and ambiguous delivery status tracking. Data integrity requires uniqueness.",
      "testable_assertion": "Adding a Recipient whose name+address combination already exists on the Shipment MUST be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Every multi-recipient Shipment MUST designate exactly one Primary Recipient.",
      "invariant": true,
      "invariant_justification": "External systems, courier fallback logic, and billing all require a single authoritative contact. Without a Primary Recipient, these processes have no deterministic fallback, leading to system-level ambiguity.",
      "testable_assertion": "A Shipment with multiple Recipients but no Primary Recipient flag, or with more than one Primary Recipient flag, MUST fail validation."
    },
    {
      "id": "BR-5",
      "rule": "Delivery Preferences are optional per Recipient. If not specified, system defaults apply.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy convenience. A VP could change the default preferences or make them mandatory without corrupting data integrity.",
      "testable_assertion": "A Recipient with no explicit Delivery Preferences MUST inherit the platform's default delivery preferences, and the Shipment MUST still be valid."
    },
    {
      "id": "BR-6",
      "rule": "Existing single-recipient Shipments MUST remain fully functional without modification after the model change. The sole Recipient is implicitly the Primary Recipient.",
      "invariant": true,
      "invariant_justification": "2 million production Shipments with established data contracts cannot be broken. This is a data integrity and backward-compatibility invariant — violating it corrupts the live system.",
      "testable_assertion": "All existing Shipments with one Recipient MUST be queryable, updatable, and deliverable using both old and new code paths without data migration errors."
    },
    {
      "id": "BR-7",
      "rule": "The aggregate Shipment status derivation rule for multi-recipient Shipments must be explicitly defined: a Shipment is 'Delivered' only when ALL Recipients have received their delivery.",
      "invariant": false,
      "invariant_justification": "This is a business policy decision about what 'delivered' means. The product team could decide 'any recipient delivered' is sufficient. The rule itself is not a data integrity constraint but a business definition.",
      "testable_assertion": "A Shipment with 3 Recipients where only 2 have status 'Delivered' MUST NOT have aggregate status 'Delivered'. It should show 'Partially Delivered' or remain 'In Transit'."
    },
    {
      "id": "BR-8",
      "rule": "Delivery Attempts MUST be scoped to a specific Recipient, not to the Shipment as a whole.",
      "invariant": true,
      "invariant_justification": "A delivery attempt to 123 Main St for Recipient A is a different physical event than an attempt to 456 Oak Ave for Recipient B. Conflating them corrupts delivery tracking and proof-of-delivery records.",
      "testable_assertion": "Every DeliveryAttempt event MUST reference both a ShipmentId and a RecipientId. A DeliveryAttempt with no RecipientId MUST be rejected."
    },
    {
      "id": "BR-9",
      "rule": "External partner APIs MUST continue to receive shipment data in a backward-compatible format until partners have migrated to the new contract.",
      "invariant": false,
      "invariant_justification": "This is a business relationship and integration policy, not a data integrity constraint. It can be relaxed once partners upgrade, but violating it prematurely breaks partner SLAs.",
      "testable_assertion": "Partner API responses for multi-recipient Shipments MUST include the Primary Recipient in the legacy single-recipient field, and optionally include the full Recipient list in a new field."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A user is creating a new Shipment",
      "when": "They submit the Shipment with one or more Recipients, each having name, address, phone, and optional delivery preferences",
      "then": "The Shipment is created successfully with all Recipients persisted, and exactly one is marked as Primary Recipient"
    },
    {
      "id": "AC-2",
      "given": "A user is creating a new Shipment",
      "when": "They submit the Shipment with zero Recipients",
      "then": "The system rejects the request with a validation error: 'Shipment must have at least one Recipient'"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the model change",
      "when": "The system loads it after the model evolution is deployed",
      "then": "The Shipment is fully functional, the existing Recipient is treated as Primary Recipient, and no data migration is required for read operations"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment with 3 Recipients",
      "when": "Delivery is completed to 2 of 3 Recipients",
      "then": "The Shipment aggregate status is 'Partially Delivered' (not 'Delivered'), and individual Recipient delivery statuses are tracked independently"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment exists",
      "when": "An external partner requests Shipment data via the existing API",
      "then": "The response includes the Primary Recipient in the legacy single-recipient fields and all Recipients in a new 'recipients' array field (backward-compatible envelope)"
    },
    {
      "id": "AC-6",
      "given": "A courier is making a delivery attempt on a multi-recipient Shipment",
      "when": "The attempt is recorded",
      "then": "The DeliveryAttempt event references the specific RecipientId, not just the ShipmentId"
    },
    {
      "id": "AC-7",
      "given": "A user tries to add a Recipient to a Shipment",
      "when": "A Recipient with the same name and address already exists on that Shipment",
      "then": "The system rejects the addition with a duplicate Recipient error"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment with 2 Recipients",
      "when": "A user removes one Recipient, leaving exactly one",
      "then": "The removal succeeds and the remaining Recipient is automatically designated as Primary Recipient"
    },
    {
      "id": "AC-9",
      "given": "A multi-recipient Shipment with 1 Recipient",
      "when": "A user attempts to remove the last Recipient",
      "then": "The system rejects the removal with error: 'Cannot remove last Recipient from Shipment'"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Shipment in transit when a new Recipient is added",
      "expected_behavior": "The system must decide whether Recipients can be added/removed after a Shipment enters 'In Transit' status. Recommendation: lock Recipient list once the Shipment is dispatched to prevent mid-route chaos for couriers. This needs explicit product team confirmation."
    },
    {
      "scenario": "Two Recipients at the same physical address but different people",
      "expected_behavior": "This is a valid scenario (e.g., two people in the same office building). The uniqueness constraint on name+address permits this since names differ. Each gets their own delivery attempt and notification."
    },
    {
      "scenario": "Primary Recipient is removed from a multi-recipient Shipment",
      "expected_behavior": "The system must auto-promote another Recipient to Primary, or reject the removal until a new Primary is designated. Recommendation: reject removal and require explicit Primary reassignment first."
    },
    {
      "scenario": "Partner API receives a Shipment with 50 Recipients",
      "expected_behavior": "The legacy single-recipient field returns the Primary Recipient. The partner must opt into the new API version to see all Recipients. Consider imposing a reasonable upper bound on Recipient count (e.g., 20) to prevent abuse."
    },
    {
      "scenario": "Notification delivery for multi-recipient Shipments",
      "expected_behavior": "Each Recipient receives their own delivery notifications based on their own delivery preferences and contact info. Notifications must not leak one Recipient's information to another (privacy constraint)."
    },
    {
      "scenario": "Billing and cost allocation across multiple Recipients",
      "expected_behavior": "If each Recipient is at a different address, the Shipment may require multiple delivery stops, increasing cost. The billing model must account for per-stop or per-Recipient pricing. This is undefined in the current spec."
    },
    {
      "scenario": "Data migration for 2 million existing Shipments",
      "expected_behavior": "Lazy migration is recommended: existing records are read-compatible by treating the embedded Recipient as a single-element Recipients array with Primary=true. Write-path migration occurs on next update. Avoid a big-bang migration of 2M rows."
    },
    {
      "scenario": "Partial delivery failure — some Recipients delivered, some permanently failed",
      "expected_behavior": "A new terminal state may be needed (e.g., 'Partially Failed') for Shipments where some Recipients received delivery but others exhausted all retry attempts. The current status model likely has no such state."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient Shipments introduce new pricing complexity. A single Shipment to multiple addresses means multiple delivery stops — the cost model must shift from per-shipment to per-shipment-plus-per-stop or per-recipient pricing. Without this, the company absorbs additional courier costs on every multi-recipient Shipment. Conversely, this feature enables higher-value B2B use cases (e.g., one order distributed to multiple offices) that can increase average order value.",
    "operational": "Courier dispatch and route optimization must account for multiple stops per Shipment. Delivery tracking becomes more complex — operations teams need dashboards showing per-Recipient status within a Shipment. Support teams need new tooling to handle 'partially delivered' escalations. Data migration of 2M records must be handled without downtime.",
    "user": "Senders gain flexibility to ship to multiple Recipients in a single transaction, reducing friction for B2B and gift-sending use cases. However, the UX complexity increases — senders must manage a Recipient list, understand Primary Recipient designation, and track multiple delivery statuses. Recipients themselves see no change unless the notification system leaks cross-Recipient info (privacy risk).",
    "risk": "HIGH. This is a foundational model change to the core aggregate. Risks include: (1) Breaking 2M existing Shipments if backward compatibility is not handled correctly. (2) Breaking external partner integrations if API versioning is botched. (3) Introducing an inconsistent Shipment status model that confuses operations. (4) Privacy violations if Recipient data leaks across Recipients. (5) Billing model gaps causing revenue leakage on multi-stop Shipments.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "Gain multi-recipient capability but face increased UI complexity. Must understand Primary Recipient concept." },
      { "group": "Recipients", "impact": "Minimal direct impact. Privacy risk if cross-Recipient data leaks in notifications or tracking pages." },
      { "group": "Couriers / Drivers", "impact": "Significant operational change. A single Shipment may now require multiple stops. Dispatch and routing tools must surface per-Recipient delivery instructions." },
      { "group": "Operations / Support", "impact": "Need new tooling for partially delivered states, per-Recipient tracking, and escalation workflows." },
      { "group": "External Partners", "impact": "API contract changes require versioning strategy. Partners on legacy API must not break. Migration timeline and communication needed." },
      { "group": "Finance / Billing", "impact": "Pricing model must evolve to account for multi-stop deliveries. Without it, revenue leakage occurs on every multi-recipient Shipment." },
      { "group": "Engineering", "impact": "Core aggregate redesign, data migration strategy, API versioning, new status state machine, and updates to every consumer of the Shipment model." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is thin on critical business decisions: aggregate delivery status semantics (all-delivered vs any-delivered), billing model for multi-stop, Recipient mutability after dispatch, upper bound on Recipients, and whether this is a same-package-multiple-stops or split-package model. These ambiguities directly affect invariants, state machines, and pricing — all foundational. External partner API impact is real but strategy is unspecified. I have high confidence on the data integrity rules (BR-1 through BR-3) and backward compatibility requirements (BR-6), but low confidence on status derivation (BR-7) and billing/pricing implications.",
    "high_confidence_areas": [
      "Minimum one Recipient invariant",
      "Per-Recipient data completeness requirements (name, address, phone)",
      "Backward compatibility requirement for 2M existing Shipments",
      "Need for API versioning / adapter layer for external partners",
      "Delivery Attempts must be scoped to a specific Recipient"
    ],
    "low_confidence_areas": [
      "Aggregate Shipment status derivation rule (all-delivered vs any-delivered vs custom)",
      "Whether Recipients can be mutated after Shipment is dispatched",
      "Billing and pricing model for multi-stop Shipments",
      "Upper bound on number of Recipients per Shipment",
      "Whether this is one physical package with multiple handoffs or multiple packages under one Shipment",
      "Privacy model — what data is shared on shared tracking pages"
    ],
    "assumptions": [
      "This is a single physical package delivered to multiple addresses in sequence, not a split-package model",
      "Delivery Preferences are lightweight value objects (time window, signature required, safe place) not complex workflow definitions",
      "The Primary Recipient concept is acceptable to the product team — it was not in the spec but is required for backward compatibility",
      "Lazy data migration is acceptable vs big-bang migration",
      "External partners are on contractual SLAs that prevent breaking API changes without notice"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'Delivered' means for a multi-recipient Shipment. Is the Shipment delivered when ALL Recipients have received, or when ANY one has? This fundamentally changes the status state machine, SLA calculations, and operational dashboards.",
      "affected_stakeholders": ["Operations", "Senders", "Finance", "Engineering"],
      "options": [
        "ALL Recipients must receive before Shipment is 'Delivered' (strict, introduces 'Partially Delivered' state)",
        "ANY Recipient receiving marks Shipment as 'Delivered' (loose, simpler but misleading)",
        "Per-Recipient status is tracked independently; Shipment aggregate status is derived (most flexible, most complex)"
      ],
      "recommendation": "Option C — track per-Recipient status independently and derive aggregate status. This is the most domain-faithful approach and avoids painting ourselves into a corner. But the derivation rule itself still needs product team sign-off."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether this is a single physical package handed to multiple people at different addresses (sequential delivery), or a split-shipment model where the package contents are divided. These are fundamentally different logistics operations.",
      "affected_stakeholders": ["Couriers", "Operations", "Senders", "Engineering"],
      "options": [
        "Single package, multiple delivery stops (courier carries one package, delivers to each Recipient in turn)",
        "Split package — contents divided at a hub, separate packages to each Recipient",
        "Both models supported, chosen per Shipment"
      ],
      "recommendation": "Clarify with the product team immediately. This changes routing, packaging, billing, and the entire physical fulfillment model. Cannot proceed with domain modeling until this is resolved."
    },
    {
      "type": "missing_context",
      "description": "No billing or pricing model defined for multi-recipient Shipments. A single Shipment to 5 addresses costs significantly more in courier time and fuel than a single-address Shipment. Without a pricing model, every multi-recipient Shipment is a revenue loss.",
      "affected_stakeholders": ["Finance", "Senders", "Operations"],
      "options": [
        "Flat rate per Shipment regardless of Recipient count (simple, but causes revenue leakage)",
        "Base rate + per-additional-Recipient surcharge",
        "Per-stop pricing based on route distance"
      ],
      "recommendation": "Option B as a starting point — base rate plus surcharge per additional Recipient. Simple to implement, communicates cost to senders. Route-based pricing (Option C) is more accurate but requires routing engine integration."
    },
    {
      "type": "ambiguity",
      "description": "Can Recipients be added or removed from a Shipment after it has been dispatched (status = 'In Transit')? This has massive operational implications for couriers already en route.",
      "affected_stakeholders": ["Couriers", "Senders", "Operations"],
      "options": [
        "Recipient list is locked once Shipment is dispatched — no changes after 'In Transit'",
        "Recipients can be added/removed at any point, with real-time courier notification",
        "Recipients can be removed (cancel a stop) but not added after dispatch"
      ],
      "recommendation": "Option A for initial release — lock the Recipient list at dispatch. Mutable Recipients mid-route is a V2 feature that requires real-time courier communication infrastructure."
    }
  ],

  "rejection_reasons": []
}

